INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES ("", 1, 6014, 3, "drama_talk_surprise_in_shy", "drama_talk_surprise_loop_shy", 6, 0, 129811, "", 0.2);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES ("", "", 6015, 21, "vo_minigame_1013_top_talk_6_002", 0, 6, 0, "vo_minigame_1013", "", "");
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (0.3, 0, 6016, 11, "いやいや何でもない！\nあたしは別に変なこと\n考えてないからな！\nそれより訓練だっ！", 1, 6, 9, 129811, 0, 0);
